I'm going to hold off on merging this for now. This isn't a common enough use case to justify the added API surface area. You can easily get this behavior using a `post_load` method.

```python
from marshmallow import Schema, fields, post_load

class TolerantSchema(Schema):

    @post_load(pass_original=True)
    def add_additional_data(self, valid_data, original_data):
        additional_keys = set(original_data) - set(valid_data)
        for key in additional_keys:
            valid_data[key] = original_data[key]
        return valid_data


class MySchema(TolerantSchema):
    known_field = fields.Field(required=True)


schema = MySchema(strict=True)

print(schema.load({'known_field': 'foo', 'additional_field': 'bar'}).data)
# {'known_field': 'foo', 'additional_field': 'bar'}
```

Thanks anyway for sending a PR!

@vovanbo Apologies for the delayed response. Here's a stab at a `DictField` that might meet your use case:

```python
from marshmallow import Schema, fields, validate

class DictField(fields.Field):
    
    def __init__(self, key_field, nested_field, *args, **kwargs):
        fields.Field.__init__(self, *args, **kwargs)
        self.key_field = key_field
        self.nested_field = nested_field
        
    def _deserialize(self, value):
        ret = {}
        for key, val in value.items():
            k = self.key_field.deserialize(key)
            v = self.nested_field.deserialize(val)
            ret[k] = v
        return ret
    
    def _serialize(self, value, attr, obj):
        ret = {}
        for key, val in value.items():
            k = self.key_field._serialize(key, attr, obj)
            v = self.nested_field.serialize(key, self.get_value(attr, obj))
            ret[k] = v
        return ret
        

class MetricSchema(Schema):
    value = fields.Float()
    date = fields.DateTime()
    
class UserSchema(Schema):
    metrics = DictField(
        fields.Str(validate=validate.Regexp(r'^[a-zA-Z]+$')), 
        fields.Nested(MetricSchema)
    )
    
metrics = {
    "metrics": {
        "firstMetricName": {
            "value": 100,
            "date": "2015-01-09T04:33:17+00:00"
        },
        "secondMetricName": {
            "value": 110,
            "date": "2015-01-09T04:33:17+00:00"
        }
    }
}

s = UserSchema(strict=True)
s.load(metrics).data
# {'metrics': {'firstMetricName': {'value': 100.0,
#    'date': datetime.datetime(2015, 1, 9, 4, 33, 17, tzinfo=tzutc())},
#   'secondMetricName': {'value': 110.0,
#    'date': datetime.datetime(2015, 1, 9, 4, 33, 17, tzinfo=tzutc())}}}
```

Don't take this as an "official" answer, I may be wrong.

Based on my experience you can use several exploration techniques at the same time, but only one of them can override the `step_path` function. 

LoopLimiter didn't worked for me, here is a basic implementation, you can try with this, till the official get fixed. It's more resource consuming, needs a CFGAccurate, and currently drops the paths after the first loop, but that can be modified easily.

```python
import angr 
class LoopLim(angr.exploration_techniques.ExplorationTechnique):
    def __init__(self, cfg):
        super(LoopLim, self).__init__()
        self.cfg = cfg

    def setup(self, pg):
        if 'loop' not in pg.stashes:
            pg.stashes['loop'] = []

    def step(self, pg, stash, **kwargs):
        looping = set()
        for path in pg.active:
            call_stack_suffix = path.callstack.stack_suffix(self.cfg.context_sensitivity_level)
            block_id = self.cfg._generate_block_id(call_stack_suffix, path.addr, False, continue_at=None)
            if 'xx' not in path.info:
                path.info['xx'] = set()
            if block_id in path.info['xx']:
                looping.add(path)
            path.info['xx'].add(block_id)

        pg.move(from_stash='active', to_stash='_DROP', filter_func=lambda p: p in looping)
        pg = pg.step(stash=stash, **kwargs)
        return pg
```

